/**
 * executableLoader.js
 *
 * Sandbox loader for executable rules generated by the evolution loop.
 * Rules are small JS modules in data/evolved/executables/ that can inject
 * system messages or prepend context based on tool call patterns.
 *
 * Category-based deduplication: only one rule per category fires per invocation.
 * If two rules in the same category both match, highest confidence wins.
 *
 * Phase 1: Loads and fires rules. Rule generation is Phase 4.
 */

const fs = require('fs');
const path = require('path');

class ExecutableLoader {
    /**
     * @param {string} executablesDir - Path to data/evolved/executables/
     * @param {object} logger - Plugin logger
     */
    constructor(executablesDir, logger) {
        this.executablesDir = executablesDir;
        this.logger = logger;

        // Cached loaded rules
        this.rules = [];
        this.lastLoadTime = 0;
        this.reloadIntervalMs = 60000; // Reload every 60s

        this._ensureDir(executablesDir);
    }

    /**
     * Get summaries of active rules (for context injection).
     * @returns {Array<{category: string, description: string}>}
     */
    getActiveRules() {
        this._maybeReload();
        return this.rules.map(r => ({
            category: r.category || 'uncategorized',
            description: r.description || r.filename
        }));
    }

    /**
     * Fire rules against an after_tool_call event.
     * Returns combined hook response (systemMessage, etc.).
     * Only one rule per category fires — highest confidence wins.
     */
    fireAfterTool(event, ctx) {
        this._maybeReload();
        if (this.rules.length === 0) return {};

        // Collect matching rules
        const matches = [];
        for (const rule of this.rules) {
            try {
                if (rule.shouldFire && rule.shouldFire(event, ctx)) {
                    matches.push(rule);
                }
            } catch (err) {
                this.logger.warn(`[CodeEvolution] Rule "${rule.filename}" shouldFire error: ${err.message}`);
            }
        }

        if (matches.length === 0) return {};

        // Deduplicate by category — highest confidence per category
        const byCategory = new Map();
        for (const match of matches) {
            const cat = match.category || 'uncategorized';
            const existing = byCategory.get(cat);
            if (!existing || (match.confidence || 0) > (existing.confidence || 0)) {
                byCategory.set(cat, match);
            }
        }

        // Execute winning rules, collect results
        const systemMessages = [];
        for (const [cat, rule] of byCategory) {
            try {
                const result = rule.execute(event, ctx);
                if (result?.systemMessage) {
                    systemMessages.push(result.systemMessage);
                }
            } catch (err) {
                this.logger.warn(`[CodeEvolution] Rule "${rule.filename}" execute error: ${err.message}`);
            }
        }

        if (systemMessages.length === 0) return {};
        return { systemMessage: systemMessages.join('\n') };
    }

    // -----------------------------------------------------------------------
    // Internal
    // -----------------------------------------------------------------------

    _maybeReload() {
        if (Date.now() - this.lastLoadTime < this.reloadIntervalMs) return;
        this._loadRules();
    }

    _loadRules() {
        this.rules = [];
        this.lastLoadTime = Date.now();

        try {
            if (!fs.existsSync(this.executablesDir)) return;

            const files = fs.readdirSync(this.executablesDir)
                .filter(f => f.endsWith('.js') && !f.startsWith('.'));

            for (const file of files) {
                try {
                    const filepath = path.join(this.executablesDir, file);
                    // Clear require cache to pick up changes
                    delete require.cache[require.resolve(filepath)];
                    const rule = require(filepath);

                    if (typeof rule.shouldFire !== 'function' || typeof rule.execute !== 'function') {
                        this.logger.warn(`[CodeEvolution] Skipping ${file}: missing shouldFire or execute`);
                        continue;
                    }

                    this.rules.push({
                        ...rule,
                        filename: file
                    });
                } catch (err) {
                    this.logger.warn(`[CodeEvolution] Failed to load rule ${file}: ${err.message}`);
                }
            }

            if (this.rules.length > 0) {
                this.logger.info(`[CodeEvolution] Loaded ${this.rules.length} executable rule(s)`);
            }
        } catch (err) {
            this.logger.warn(`[CodeEvolution] Failed to scan executables dir: ${err.message}`);
        }
    }

    _ensureDir(dir) {
        if (!fs.existsSync(dir)) {
            fs.mkdirSync(dir, { recursive: true });
        }
    }
}

module.exports = ExecutableLoader;
